const { execSync } = require('child_process');
const projectRoot = $env.LOTTERY_AUTO_ROOT || '/path/to/lottery-pension-auto';
try {
  execSync(
    `/usr/bin/python3 ${projectRoot}/scripts/lotto645_runner.py`,
    {
      cwd: projectRoot,
      timeout: 300000,
      env: {
        PATH: '/usr/local/bin:/usr/bin:/bin:/usr/sbin:/sbin',
        HOME: $env.HOME || '',
        GOOGLE_SPREADSHEET_ID: $env.GOOGLE_SPREADSHEET_ID || '',
        GOOGLE_SERVICE_ACCOUNT_PATH: $env.GOOGLE_SERVICE_ACCOUNT_PATH || `${projectRoot}/config/service_account.json`,
        DHLOTTERY_ID: $env.DHLOTTERY_ID || '',
        DHLOTTERY_PW: $env.DHLOTTERY_PW || '',
        TELEGRAM_CHAT_ID: $env.TELEGRAM_CHAT_ID || '',
        TELEGRAM_BOT_TOKEN: $env.TELEGRAM_BOT_TOKEN || ''
      }
    }
  );
  return [{ json: { exitCode: 0 } }];
} catch (e) {
  return [{ json: { exitCode: e.status || 1 } }];
}
